sql:
SELECT MAX(amount) AS max_transaction_amount
FROM user_transactions
WHERE user_id = 0;

external_knowledge:
- "top three" refers to the transactions with the highest total volume in USD; 
- "last month" refers to the last 30 days from the current date; 
- "details" include user ID, user name, cryptocurrency ID, and cryptocurrency name.

sql:
SELECT SUM(balance) AS total_balance
FROM user_wallets
WHERE crypto_id = 1;

SELECT COUNT(*) AS transaction_count
FROM user_transactions
WHERE user_id = 0 AND crypto_id = 0;

SELECT COUNT(*)
FROM cryptocurrencies
WHERE category = (SELECT category_id FROM categories WHERE category_name = 'Payment');

SELECT balance
FROM user_wallets
WHERE is_active = 1;
